def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 2:
            priorities[i] = ratio ** 3
        elif 1 < ratio <= 2:
            priorities[i] = ratio * 15 - 5
        else:
            score = 0
            for j in range(1, 10):
                term = ((-1) ** (j+1)) * (ratio ** j) / (j ** 1.5)
                score += term
                if abs(term) < 1e-5:
                    break
            if capacity < item * 1.5:
                score *= 2
            elif capacity < item * 3:
                score *= 1.2
            else:
                score *= 0.8
            if i % 2 == 0:
                score += 0.1 * np.sin(i)
            else:
                score -= 0.1 * np.cos(i)
            priorities[i] = -score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
        for i in range(len(priorities)):
            if not np.isfinite(priorities[i]):
                priorities[i] = max_priority + 50 + (i % 5) * 10
    else:
        priorities.fill(1000)
    for i in range(len(priorities)):
        if priorities[i] < 0 and i % 3 == 0:
            priorities[i] *= 1.1
        elif priorities[i] > 0 and i % 4 == 0:
            priorities[i] *= 0.9
    return priorities
